  1→import { stepCountIs, streamText, type ModelMessage } from "ai";
  2→import { RecordId, Surreal } from "surrealdb";
  3→import type { ExtractedEntity, ExtractedRelationship, OnboardingState } from "../../shared/contracts";
  4→import { logInfo, logError } from "../http/observability";
  5→import { buildChatContext, buildSystemPrompt, type ChatContext } from "./context";
  6→import { createChatAgentTools } from "./tools";
  7→
  8→type ConversationMessage = {
  9→  role: "user" | "assistant";
 10→  text: string;
 11→};
 12→
 13→type CollectedEntity = ExtractedEntity;
 14→type CollectedRelationship = ExtractedRelationship;
 15→
 16→export type ChatAgentResult = {
 17→  text: string;
 18→  collectedEntities: CollectedEntity[];
 19→  collectedRelationships: CollectedRelationship[];
 20→  toolCalls: Array<{ name: string; args: Record<string, unknown> }>;
 21→};
 22→
 23→export async function runChatAgent(input: {
 24→  surreal: Surreal;
 25→  model: any;
 26→  pmAgentModel: any;
 27→  analyticsAgentModel: any;
 28→  analyticsSurreal: Surreal;
 29→  embeddingModel: any;
 30→  embeddingDimension: number;
 31→  extractionModelId: string;
 32→  extractionModel: any;
 33→  extractionStoreThreshold: number;
 34→  conversationRecord: RecordId<"conversation", string>;
 35→  workspaceRecord: RecordId<"workspace", string>;
 36→  currentMessageRecord: RecordId<"message", string>;
 37→  latestUserText: string;
 38→  workspaceOwnerRecord?: RecordId<"person", string>;
 39→  personRecord: RecordId<"person", string>;
 40→  userMessageEmbedding?: number[];
 41→  inheritedEntityIds?: RecordId[];
 42→  discussesRecord?: RecordId;
 43→  messages: ConversationMessage[];
 44→  isOnboarding?: boolean;
 45→  onboardingState?: OnboardingState;
 46→  workspaceName: string;
 47→  workspaceDescription?: string;
 48→  onToken: (token: string) => Promise<void> | void;
 49→  onReasoning?: (token: string) => Promise<void> | void;
 50→}): Promise<ChatAgentResult> {
 51→  const context = await buildChatContext({
 52→    surreal: input.surreal,
 53→    conversationRecord: input.conversationRecord,
 54→    workspaceRecord: input.workspaceRecord,
 55→    ...(input.workspaceDescription ? { workspaceDescription: input.workspaceDescription } : {}),
 56→    ...(input.userMessageEmbedding ? { userMessageEmbedding: input.userMessageEmbedding } : {}),
 57→    ...(input.inheritedEntityIds && input.inheritedEntityIds.length > 0
 58→      ? { inheritedEntityIds: input.inheritedEntityIds }
 59→      : {}),
 60→    ...(input.discussesRecord ? { discussesRecord: input.discussesRecord } : {}),
 61→  });
 62→
 63→  const system = buildSystemPrompt(context, {
 64→    isOnboarding: input.isOnboarding,
 65→    onboardingState: input.onboardingState,
 66→    workspaceName: input.workspaceName,
 67→  });
 68→
 69→  const modelMessages: ModelMessage[] = input.messages.map((message) => ({
 70→    role: message.role,
 71→    content: message.text,
 72→  }));
 73→
 74→  const result = streamText({
 75→    model: input.model,
 76→    system,
 77→    messages: modelMessages,
 78→    tools: createChatAgentTools({
 79→      surreal: input.surreal,
 80→      pmAgentModel: input.pmAgentModel,
 81→      analyticsAgentModel: input.analyticsAgentModel,
 82→      analyticsSurreal: input.analyticsSurreal,
 83→      embeddingModel: input.embeddingModel,
 84→      embeddingDimension: input.embeddingDimension,
 85→      extractionModelId: input.extractionModelId,
 86→      extractionModel: input.extractionModel,
 87→      extractionStoreThreshold: input.extractionStoreThreshold,
 88→    }),
 89→    experimental_context: {
 90→      actor: "chat_agent",
 91→      humanPresent: true,
 92→      workspaceRecord: input.workspaceRecord,
 93→      conversationRecord: input.conversationRecord,
 94→      currentMessageRecord: input.currentMessageRecord,
 95→      latestUserText: input.latestUserText,
 96→      ...(input.workspaceOwnerRecord ? { workspaceOwnerRecord: input.workspaceOwnerRecord } : {}),
 97→      personRecord: input.personRecord,
 98→    },
 99→    stopWhen: stepCountIs(5),
100→  });
101→
102→  let text = "";
103→  const collectedEntities: CollectedEntity[] = [];
104→  const collectedRelationships: CollectedRelationship[] = [];
105→  const toolCalls: Array<{ name: string; args: Record<string, unknown> }> = [];
106→
107→  for await (const part of result.fullStream) {
108→    if (part.type === "reasoning-delta") {
109→      await input.onReasoning?.(part.text);
110→      continue;
111→    }
112→
113→    if (part.type === "text-delta") {
114→      text = `${text}${part.text}`;
115→      await input.onToken(part.text);
116→      continue;
117→    }
118→
119→    if (part.type === "tool-call") {
120→      logInfo("chat.agent.tool_call", "Chat agent invoked tool", part);
121→      toolCalls.push({ name: part.toolName, args: (part as any).input as Record<string, unknown> });
122→    }
123→
124→    if (part.type === "tool-result") {
125→      logInfo("chat.agent.tool_result", "Chat agent tool returned", part);
126→      const toolResult = part.output as Record<string, unknown> | undefined;
127→      if (toolResult) {
128→        if (Array.isArray(toolResult.extracted_entities)) {
129→          collectedEntities.push(...(toolResult.extracted_entities as CollectedEntity[]));
130→        }
131→        if (Array.isArray(toolResult.extracted_relationships)) {
132→          collectedRelationships.push(...(toolResult.extracted_relationships as CollectedRelationship[]));
133→        }
134→      }
135→    }
136→
137→    if (part.type === "error") {
138→      logError("chat.agent.stream_error", "Chat agent stream error", part.error, {});
139→    }
140→  }
141→
142→  if (text.trim().length === 0) {
143→    text = await result.text;
